import {SelectButton} from "primereact/selectbutton";
import type {FilterEl} from "../Filter";
import type {IButtonsFilter} from "@lmb-it/kitsconcerto-types";

const ButtonsFilterElement: FilterEl<{
  list:IButtonsFilter['list'];
  isMultiple?: boolean;
}> = ({ isMultiple, list, ...options }) => {
  return (
    <SelectButton
      value={options.value}
      optionValue={"value"}
      optionLabel={"label"}
      multiple={isMultiple}
      style={{
        borderRadius: 0,
      }}
      onChange={(e) => options.filterApplyCallback(e.value)}
      options={list}
    />
  );
};

export default ButtonsFilterElement;
